+@MainActor
+private protocol MenuItemMeasuring: AnyObject {
+    func measuredHeight(width: CGFloat) -> CGFloat
+}
+
+@MainActor
+private protocol MenuItemHighlighting: AnyObject {
+    func setHighlighted(_ highlighted: Bool)
+}
